import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./register.css"
function Registration() {
    const navigate = useNavigate()
  let [nameinput, changenameinput] = useState("")
  let [passwordinput, changepasswordinput] = useState("")
  let [cityinput, changecityinput] = useState("")
  const [toasts, setToasts] = useState([]);
  function sendtologin() {
    navigate("/login")
  }
  function getinputn(e) {
    changenameinput(e.target.value)
  }
  function getinputp(e) {
    changepasswordinput(e.target.value)
  }
  function getinputc(e) {
    changecityinput(e.target.value)
  }
  async function func1() {
  async function func1() {
  if (
    nameinput.trim() === "" ||
    passwordinput.trim() === "" ||
    cityinput.trim() === ""
  ) {
    showToast("Please fill in all fields", "error");
    return;
  }

  if (!nameinput.includes("@")) {
    showToast("Enter a valid email address", "error");
    return;
  }

  if (passwordinput.length < 6) {
    showToast("Password must be at least 6 characters", "error");
    return;
  }

  try {
    let emailCheckResponse = await fetch("http://localhost:5000/checkemail", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ emailforcheck: nameinput }),
    });

    let emailExists = await emailCheckResponse.json();

    if (emailExists == false) {
      showToast("Email already exists", "error");
      return;
    }

    let registerResponse = await fetch("http://localhost:5000/registration", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({
        nameforreg: nameinput,
        passwordforreg: passwordinput,
        cityforreg: cityinput,
      }),
    });

    if (registerResponse.ok) {
      showToast("Account created successfully", "success");
    } else {
      showToast("Registration failed", "error");
    }
  } catch (error) {
    showToast("Server error. Try again.", "error");
    console.log(error);
  }
}
    }
 function showToast(message, type = "error") {
  const id = Date.now() + Math.random();

  setToasts((prev) => [...prev, { id, message, type }]);

  setTimeout(() => {
    setToasts((prev) => prev.filter((toast) => toast.id !== id));
  }, 3000);
}

function removeToast(id) {
  setToasts((prev) => prev.filter((toast) => toast.id !== id));
}
  return (
  <div className="register-page">
    <div className="toast-container">
      {toasts.map((toast) => (
        <div key={toast.id} className={`toast ${toast.type}`}>
          <div className="toast-content">
            <span className="toast-message">{toast.message}</span>
            <button
              className="toast-close"
              onClick={() => removeToast(toast.id)}
            >
              ×
            </button>
          </div>
          <div className="toast-progress"></div>
        </div>
      ))}
    </div>

    <div className="register-card">
      <h1>Create an account</h1>

      <label>Email</label>
      <input value={nameinput} onChange={(e) => getinputn(e)} />

      <label>Password</label>
      <input
        value={passwordinput}
        onChange={(e) => getinputp(e)}
        type="password"
      />

      <label>City</label>
      <input value={cityinput} onChange={(e) => getinputc(e)} />

      <button onClick={func1}>Register</button>

      <a onClick={sendtologin}>Already registered?</a>
    </div>
  </div>
);
}
export default Registration
